fn set_ops(a: List[Int], b: List[Int]) -> Tuple[List[Int], List[Int], List[Int]]:
    var sa = Set[Int]()
    var sb = Set[Int]()
    for x in a: sa.add(x[])
    for x in b: sb.add(x[])
    var union_set = sa | sb
    var inter_set = sa & sb
    var diff_set  = sa - sb
    var u = List[Int]()
    var inter = List[Int]()
    var diff = List[Int]()
    for x in union_set: u.append(x[])
    for x in inter_set: inter.append(x[])
    for x in diff_set:  diff.append(x[])
    sort(u); sort(inter); sort(diff)
    return (u, inter, diff)
